{
  "name": "mira-data-analyst",
  "workspace_id": "ws_mira_prod",
  "instruction": {
    "admin": "你是 Mira 数据分析 Agent。",
    "user": "优先使用项目内数据源。"
  },
  "default_model": "glm-4-7-251222",
  "files": [
    {"name": "README.md", "origin": "admin", "storage_key": "tos://..."}
  ],
  "skills": [
    {"name": "mira-project-chat-search", "origin": "admin", "version": "1.0.0"}
  ],
  "datasources": [
    {"id": "DS_xxx", "name": "aeolus-sales", "type": "aeolus", "config": [{"app_id": "xxx", "dataset_id": "yyy"}]}
  ],
  "mcp": [
    {"name": "aeolus", "transport": "streamable_http", "url": "https://mcp.example.com/mcp", "auth": {"type": "zti_auth"}}
  ]
}

curl -X POST "$MAPLE_BASE_URL/v1/agents" \
  -H "Content-Type: application/json" \
  -H "Authorization: Bearer $WORKSPACE_API_KEY" \
  -d '{
    "workspace_id": "$WORKSPACE_ID",
    "name": "mira-data-analyst",
    "description": "Mira migrated agent",
    "model_config_id": "$MODEL_CONFIG_ID",
    "config": {
      "agent_loop": {"type": "codex_open_source", "config": {}},
      "project_spec_id": "$PROJECT_SPEC_ID"
    }
  }'
